import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.D6hBiDio.js";const p=JSON.parse('{"title":"Security Statement","description":"Security and trustworthiness of the Tailscale package feed — open-source, auditable, no manual uploads","frontmatter":{"title":"Security Statement","description":"Security and trustworthiness of the Tailscale package feed — open-source, auditable, no manual uploads"},"headers":[],"relativePath":"en/reference/security.md","filePath":"en/reference/security.md","lastUpdated":1784575673000}'),s={name:"en/reference/security.md"};function o(l,e,n,c,d,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="security-statement" tabindex="-1">Security Statement <a class="header-anchor" href="#security-statement" aria-label="Permalink to &quot;Security Statement&quot;">​</a></h1><h2 id="trustworthiness" tabindex="-1">Trustworthiness <a class="header-anchor" href="#trustworthiness" aria-label="Permalink to &quot;Trustworthiness&quot;">​</a></h2><p>All packages in this feed are built automatically via GitHub Actions. The entire process is open-source, auditable, and reproducible.</p><ul><li><strong>Source code</strong> is taken directly from the <a href="https://github.com/tailscale/tailscale" target="_blank" rel="noreferrer">official Tailscale repository</a>, with <strong>no functional modifications</strong>.</li><li>Only <strong>compiler flags</strong> are added, and <a href="https://upx.github.io/" target="_blank" rel="noreferrer">UPX</a> is optionally used on most architectures to reduce package size.</li><li>All <strong>build scripts, workflows, compiler flags, and logs</strong> are fully public in the repository&#39;s <code>.github/workflows</code> and <a href="https://github.com/GuNanOvO/openwrt-tailscale/actions" target="_blank" rel="noreferrer">Actions history</a>.</li><li><strong>No manual uploads, no dynamic backend</strong> — all artifacts are generated automatically by CI and served statically via <a href="https://pages.github.com/" target="_blank" rel="noreferrer">GitHub Pages</a>.</li></ul><h2 id="recommended-verification-steps" tabindex="-1">Recommended Verification Steps <a class="header-anchor" href="#recommended-verification-steps" aria-label="Permalink to &quot;Recommended Verification Steps&quot;">​</a></h2><ol><li><strong>Review the code</strong> — Check the <a href="https://github.com/GuNanOvO/openwrt-tailscale" target="_blank" rel="noreferrer">repository</a> and <a href="https://github.com/GuNanOvO/openwrt-tailscale/actions" target="_blank" rel="noreferrer">Actions scripts and build logs</a></li><li><strong>Reproduce the build</strong> — Follow the instructions in <a href="/openwrt-tailscale/en/build/">Build Guide</a> to verify reproducibility</li><li><strong>Verify checksums</strong> — Check SHA256 checksums after downloading (available on the <a href="/openwrt-tailscale/en/packages.html">Packages page</a>)</li></ol><h2 id="disclaimer" tabindex="-1">Disclaimer <a class="header-anchor" href="#disclaimer" aria-label="Permalink to &quot;Disclaimer&quot;">​</a></h2><p>This feed is provided <strong>as-is</strong>, without any warranties, express or implied. Users are solely responsible for reviewing the source code and build process before use.</p><p>For maximum security:</p><ul><li>Prefer official sources or trusted feeds</li><li>Keep the repository watched for updates</li><li>Verify builds independently when possible</li></ul>',10)])])}const f=t(s,[["render",o]]);export{p as __pageData,f as default};
